class RateLimiter:
    """Per-IP rate limiter to mitigate amplification abuse."""

    def __init__(self, max_requests_per_second: int = 5, window_seconds: int = 10):
        self.max_requests = max_requests_per_second * window_seconds
        self.window_seconds = window_seconds
        self.requests: Dict[str, List[float]] = defaultdict(list)
        self._lock = threading.Lock()

    def is_allowed(self, ip: str) -> bool:
        now = time.time()
        with self._lock:
            # Clean old entries
            self.requests[ip] = [
                t for t in self.requests[ip]
                if now - t < self.window_seconds
            ]
            if len(self.requests[ip]) >= self.max_requests:
                return False
            self.requests[ip].append(now)
            return True

    def cleanup(self):
        """Remove stale entries periodically."""
        now = time.time()
        with self._lock:
            stale_ips = [
                ip for ip, times in self.requests.items()
                if not times or now - times[-1] > self.window_seconds * 2
            ]
            for ip in stale_ips:
                del self.requests[ip]


class GameServer:
    # Protocol constants
    QUERY_HEADER = b'\xFF\xFF\xFF\xFF'
    CHALLENGE_TIMEOUT = 30  # seconds

    # Query types
    CMD_STATUS = b'status'
    CMD_INFO = b'info'
    CMD_PLAYERS = b'players'
    CMD_RULES = b'rules'
    CMD_PING = b'ping'
    CMD_CHALLENGE = b'getchallenge'

    # Response size limit to reduce amplification factor
    MAX_RESPONSE_SIZE = 4096

    def __init__(self, host: str = "0.0.0.0", port: int = 27015):
        self.host = host
        self.port = port
        self.sock: Optional[socket.socket] = None
        self.running = False

        self.game_state = GameState()
        self.players: Dict[str, Player] = {}
        self._players_lock = threading.Lock()

        self.rate_limiter = RateLimiter(max_requests_per_second=3, window_seconds=10)

        # Challenge-response to prevent IP spoofing on large responses
        self._challenges: Dict[str, tuple] = {}  # ip:port -> (challenge, timestamp)
        self._challenge_lock = threading.Lock()

        self.start_time = time.time()

    def _generate_challenge(self, addr: tuple) -> int:
        """Generate a challenge number for an address."""
        challenge = struct.unpack('!I', hashlib.sha256(
            f"{addr}{time.time()}{id(self)}".encode()
        ).digest()[:4])[0]
        with self._challenge_lock:
            self._challenges[addr] = (challenge, time.time())
        return challenge

    def _verify_challenge(self, addr: tuple, challenge: int) -> bool:
        """Verify a challenge response to confirm the client's IP is not spoofed."""
        with self._challenge_lock:
            stored = self._challenges.get(addr)
            if stored is None:
                return False
            stored_challenge, timestamp = stored
            if time.time() - timestamp > self.CHALLENGE_TIMEOUT:
                del self._challenges[addr]
                return False
            if stored_challenge == challenge:
                del self._challenges[addr]
                return True
            return False

    def _cleanup_challenges(self):
        """Remove expired challenges."""
        now = time.time()
        with self._challenge_lock:
            expired = [
                addr for addr, (_, ts) in self._challenges.items()
                if now - ts > self.CHALLENGE_TIMEOUT
            ]
            for addr in expired:
                del self._challenges[addr]

    def add_player(self, name: str, team: str = "") -> Player:
        with self._players_lock:
            player = Player(name=name, team=team)
            self.players[name] = player
            logger.info(f"Player '{name}' joined the server.")
            return player

    def remove_player(self, name: str):
        with self._players_lock:
            if name in self.players:
                del self.players[name]
                logger.info(f"Player '{name}' left the server.")

    def update_player(self, name: str, score: int = None, ping: int = None, team: str = None):
        with self._players_lock:
            if name in self.players:
                if score is not None:
                    self.players[name].score = score
                if ping is not None:
                    self.players[name].ping = ping
                if team is not None:
                    self.players[name].team = team

    def _build_info_response(self) -> bytes:
        """Build a small info response (no challenge required)."""
        with self._players_lock:
            player_count = len(self.players)

        info = {
            "server_name": self.game_state.server_name,
            "map": self.game_state.map_name,
            "game_mode": self.game_state.game_mode,
            "players": player_count,
            "max_players": self.game_state.max_players,
            "version": self.game_state.server_version,
            "password": self.game_state.password_protected,
        }
        return self.QUERY_HEADER + b'infoResponse\n' + json.dumps(info).encode()

    def _build_status_response(self) -> bytes:
        """Build full status response (requires challenge verification)."""
        with self._players_lock:
            player_list = [p.to_dict() for p in self.players.values()]

        status = {
            "server_name": self.game_state.server_name,
            "map": self.game_state.map_name,
            "game_mode": self.game_state.game_mode,
            "players": player_list,
            "player_count": len(player_list),
            "max_players": self.game_state.max_players,
            "version": self.game_state.server_version,
            "password_protected": self.game_state.password_protected,
            "time_remaining": self.game_state.time_remaining,
            "round": self.game_state.round_number,
            "score_limit": self.game_state.score_limit,
            "uptime_seconds": int(time.time() - self.start_time),
        }

        payload = json.dumps(status).encode()

        # Enforce max response size
        if len(payload) > self.MAX_RESPONSE_SIZE - 50:
            # Truncate player list if response is too large
            while len(payload) > self.MAX_RESPONSE_SIZE - 50 and player_list:
                player_list.pop()
                status["players"] = player_list
                status["player_count_truncated"] = True
                payload = json.dumps(status).encode()

        return self.QUERY_HEADER + b'statusResponse\n' + payload

    def _build_players_response(self) -> bytes:
        """Build players-only response (requires challenge)."""
        with self._players_lock:
            player_list = [p.to_dict() for p in self.players.values()]

        payload = json.dumps({"players": player_list}).encode()

        if len(payload) > self.MAX_RESPONSE_SIZE - 50:
            while len(payload) > self.MAX_RESPONSE_SIZE - 50 and player_list:
                player_list.pop()
                payload = json.dumps({
                    "players": player_list,
                    "truncated": True
                }).encode()

        return self.QUERY_HEADER + b'playersResponse\n' + payload

    def _build_rules_response(self) -> bytes:
        """Build server rules/settings response."""
        rules = {
            "map": self.game_state.map_name,
            "game_mode": self.game_state.game_mode,
            "max_players": self.game_state.max_players,
            "time_limit": self.game_state.time_limit,
            "score_limit": self.game_state.score_limit,
            "password_protected": self.game_state.password_protected,
        }
        return self.QUERY_HEADER + b'rulesResponse\n' + json.dumps(rules).encode()

    def _build_challenge_response(self, challenge: int) -> bytes:
        """Send challenge number to client."""
        return self.QUERY_HEADER + b'challengeResponse\n' + str(challenge).encode()

    def _build_pong_response(self) -> bytes:
        return self.QUERY_HEADER + b'pong'

    def _parse_query(self, data: bytes) -> tuple:
        """
        Parse incoming query.
        Returns (command, challenge_number_or_none).
        """
        if not data.startswith(self.QUERY_HEADER):
            return None, None

        payload = data[len(self.QUERY_HEADER):]

        # Split command and optional challenge
        parts = payload.split(b' ', 1)
        command = parts[0].strip().lower()
        challenge = None

        if len(parts) > 1:
            try:
                challenge = int(parts[1].strip())
            except (ValueError, IndexError):
                challenge = None

        return command, challenge

    def _handle_query(self, data: bytes, addr: tuple):
        """Process a single query and return response bytes or None."""
        ip = addr[0]

        # Rate limiting
        if not self.rate_limiter.is_allowed(ip):
            logger.warning(f"Rate limited: {ip}")
            return None

        command, challenge_num = self._parse_query(data)
        if command is None:
            return None

        # Commands that DON'T require challenge (small responses only)
        if command == self.CMD_PING:
            # Tiny response, no challenge needed
            return self._build_pong_response()

        if command == self.CMD_CHALLENGE:
            # Client requests a challenge token
            challenge = self._generate_challenge(addr)
            logger.debug(f"Challenge issued to {addr}: {challenge}")
            return self._build_challenge_response(challenge)

        if command == self.CMD_INFO:
            # Info is small, allow without challenge but still rate-limited
            return self._build_info_response()

        # Commands that REQUIRE a valid challenge (larger responses)
        # This prevents amplification attacks with spoofed source IPs
        if command in (self.CMD_STATUS, self.CMD_PLAYERS, self.CMD_RULES):
            if challenge_num is None:
                # Tell client they need a challenge first
                challenge = self._generate_challenge(addr)
                return self._build_challenge_response(challenge)

            if not self._verify_challenge(addr, challenge_num):
                logger.warning(f"Invalid challenge from {addr} for command '{command.decode()}'")
                # Issue a new challenge
                challenge = self._generate_challenge(addr)
                return self._build_challenge_response(challenge)

            # Challenge verified - client IP is authentic
            if command == self.CMD_STATUS:
                return self._build_status_response()
            elif command == self.CMD_PLAYERS:
                return self._build_players_response()
            elif command == self.CMD_RULES:
                return self._build_rules_response()

        logger.debug(f"Unknown command from {addr}: {command}")
        return None

    def _maintenance_loop(self):
        """Periodic maintenance tasks."""
        while self.running:
            time.sleep(30)
            self.rate_limiter.cleanup()
            self._cleanup_challenges()

            # Update game time remaining (simulation)
            if self.game_state.time_remaining > 0:
                self.game_state.time_remaining = max(
                    0, self.game_state.time_remaining - 30
                )

    def start(self):
        """Start the game server query handler."""
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.settimeout(1.0)
        self.sock.bind((self.host, self.port))

        self.running = True

        # Start maintenance thread
        maintenance_thread = threading.Thread(target=self._maintenance_loop, daemon=True)
        maintenance_thread.start()

        logger.info(f"Game server query handler started on {self.host}:{self.port}")
        logger.info(f"Server: {self.game_state.server_name}")
        logger.info(f"Map: {self.game_state.map_name} | Mode: {self.game_state.game_mode}")
        logger.info("Challenge-response anti-spoofing enabled for large queries.")
        logger.info(f"Max response size: {self.MAX_RESPONSE_SIZE} bytes")

        try:
            while self.running:
                try:
                    data, addr = self.sock.recvfrom(1024)
                    if not data:
                        continue

                    response = self._handle_query(data, addr)
                    if response:
                        # Final safety check on response size
                        if len(response) > self.MAX_RESPONSE_SIZE:
                            logger.error(f"Response too large ({len(response)} bytes), dropping")
                            continue
                        self.sock.sendto(response, addr)

                except socket.timeout:
                    continue
                except OSError as e:
                    if self.running:
                        logger.error(f"Socket error: {e}")
                        time.sleep(0.1)

        except KeyboardInterrupt:
            logger.info("Shutting down...")
        finally:
            self.stop()

    def stop(self):
        self.running = False
        if self.sock:
            self.sock.close()
            self.sock = None
        logger.info("Server stopped.")


class GameServerBrowserClient:
    """Example client that properly implements challenge-response protocol."""

    QUERY_HEADER = b'\xFF\xFF\xFF\xFF'

    def __init__(self, server_host: str = "127.0.0.1", server_port: int = 27015, timeout: float = 3.0):
        self.server_addr = (server_host, server_port)
        self.timeout = timeout
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.settimeout(timeout)

    def _send_query(self, command: str, challenge: int = None) -> bytes:
        query = self.QUERY_HEADER + command.encode()
        if challenge is not None:
            query += b' ' + str(challenge).encode()
        self.sock.sendto(query, self.server_addr)
        data, _ = self.sock.recvfrom(8192)
        return data

    def _parse_response(self, data: bytes) -> tuple:
        """Returns (response_type, payload_str)."""
        if not data.startswith(self.QUERY_HEADER):
            return None, None
        payload = data[len(self.QUERY_HEADER):]
        parts = payload.split(b'\n', 1)
        resp_type = parts[0].decode()
        body = parts[1].decode() if len(parts) > 1 else ""
        return resp_type, body

    def _query_with_challenge(self, command: str) -> dict:
        """
        Perform a challenge-response query.
        1. Send command (server responds with challenge)
        2. Resend command with challenge number
        3. Receive actual response
        """
        # Step 1: Request (will get challenge back)
        data = self._send_query(command)
        resp_type, body = self._parse_response(data)

        if resp_type == "challengeResponse":
            challenge = int(body.strip())
            # Step 2: Send with challenge
            data = self._send_query(command, challenge)
            resp_type, body = self._parse_response(data)

        if body:
            return json.loads(body)
        return {}

    def ping(self) -> float:
        """Ping the server and return round-trip time in ms."""
        start = time.time()
        data = self._send_query("ping")
        rtt = (time.time() - start) * 1000
        resp_type, _ = self._parse_response(data)
        if resp_type == "pong":
            return rtt
        return -1

    def get_info(self) -> dict:
        """Get basic server info (no challenge required)."""
        data = self._send_query("info")
        resp_type, body = self._parse_response(data)
        if resp_type == "infoResponse" and body:
            return json.loads(body)
        return {}

    def get_status(self) -> dict:
        """Get full server status with player list (challenge required)."""
        return self._query_with_challenge("status")

    def get_players(self) -> dict:
        """Get player list (challenge required)."""
        return self._query_with_challenge("players")

    def get_rules(self) -> dict:
        """Get server rules (challenge required)."""
        return self._query_with_challenge("rules")

    def close(self):
        self.sock.close()


